{
  "name": "Connecticut Energy Assistance Program (CEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Annual household income at or below 60% of state median income: 1: $47,764; 2: $62,460; 3: $77,157; 4: $91,854; 5: $106,550; 6: $121,247; 7: $124,002; 8: $126,758. Categorical eligibility if household receives SNAP, SSI, TANF/TFA, State Supplement, or Refugee Cash Assistance.",
    "asset_limits": "No liquid assets test for the 2025-2026 program year.",
    "other_requirements": ["Connecticut resident", "Social Security Number required for almost all household members (exceptions may apply)", "Proof of income if not categorically eligible: last 30 days or 4 consecutive weeks in last 3 months, or 12 months prior; self-employed need IRS Form 1040 and worksheet"]
  },
  "benefits": {
    "type": "financial",
    "value": "Basic benefit: $295-$595 standard, or $345-$645 if vulnerable household member (e.g., elderly, disabled, child under 6); Crisis benefit: $425 (up to 3 per year) for deliverable fuel households in crisis; Rental assistance (heat included in rent): $75-$125. Payments to utility/fuel vendor; additional fuel deliveries, payment plans, shut-off protection, heating repairs possible. Varies by household size, income, heating source, vulnerable status.",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online via portal.ct.gov/dss (application window open for 2025-2026)", "Phone: Regional providers e.g. New Opportunities (203) 756-8151 Waterbury, (203) 235-0278 Meriden, (860) 496-0622 Torrington, (860) 738-9138 Winsted; call 211 for local provider", "In-person/mail via regional community action agencies (contact 211ct.org for locations)"],
    "processing_time": "Prioritized service for deliverable fuel crisis: fuel delivery authorization within 18 hours of eligibility determination; standard processing not specified but applications from Sep/Oct to May/June.",
    "waitlist": "Benefits available until annual funds run out; no formal waitlist mentioned.",
    "forms": ["Self-Employment Worksheet (English/Spanish)"],
    "documents": ["Proof of income (pay stubs, award letters, Social Security letters)", "Proof of residence", "Electric bill (all households)", "Heating bill (gas/oil/propane)", "Rent receipt/lease (renters)", "SSN for household members"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all CT residents meeting eligibility.",
    "regional_variations": "Administered by regional community action agencies/providers (e.g., New Opportunities Inc. for certain towns); different phone numbers and offices by area; prioritized service and processing may vary.",
    "offices_or_providers": ["Regional providers via 211ct.org or uwc.211ct.org; e.g., New Opportunities in Waterbury, Meriden, Torrington, Winsted"]
  },
  "official_source": "https://portal.ct.gov/dss/economic-security/winter-heating-assistance/energy-assistance---winter-heating",
  "gotchas": ["Must apply during season (gas/electric: Sep 1, 2025-May 29, 2026; deliverable fuels longer); funds limited and may run out", "Everyone needs electric bill; gas/deliverable fuel needs heating bill", "Vulnerable households (elderly, disabled, young children) get higher benefits—don't miss declaring this", "SSN required unless exception; Social Security income needs award letter as DSS can't verify directly", "Renters with heat included get smaller rental benefit only"],
  "data_shape_notes": "Benefits scale by household size, income, heating source (deliverable fuels get crisis extras), and vulnerable status; no asset test; regionally administered with local providers; seasonal with fund limits"
}

{
  "name": "Connecticut Health Insurance Assistance Program (HICAP/SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits for CHOICES counseling services; available to Medicare-eligible individuals (typically 65+ or under 65 with disabilities), those soon to be eligible, family members, and caregivers. Related programs like Medicare Savings Program (MSP) referenced by CHOICES have income limits effective March 1, 2026: QMB ($2,807 single/$3,806 couple), SLMB ($3,073 single/$4,166 couple), ALMB ($3,272 single/$4,437 couple). Low-Income Subsidy (LIS) info also provided.[1][3][5]",
    "asset_limits": "No asset limits or tests for CHOICES itself; assistance provided for applying to programs like MSP or LIS that may have asset rules (not detailed in sources).[1][3]",
    "other_requirements": ["Must be Connecticut resident.", "Eligible if on Medicare, soon eligible, or family/caregiver of Medicare beneficiary.", "No prior Medicare experience needed for volunteer counselors, but clients need Medicare-related questions."][1][2][5][6]
  },
  "benefits": {
    "type": "service|advocacy",
    "value": "Free, unbiased one-on-one counseling, outreach, information, referral, eligibility screening for Medicare options (Parts A/B/C/D, Medigap), enrollment help, appeals, coordinating benefits, help with costs via MSP/Medicaid/Extra Help/LIS, fraud prevention via Senior Medicare Patrol (SMP), presentations, enrollment events, health fairs. Counselors trained 8-10 hours on Medicare topics.[1][4][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-994-9422 (statewide CHOICES hotline).", "Website: portal.ct.gov/ads/programs-and-services/choices or shiphelp.org/ships/connecticut/.", "Local: Contact Area Agency on Aging (AAA) for in-person or out-of-state callers via shiphelp.org.", "Partnerships: Through 5 AAAs, Center for Medicare Advocacy, ADS."[5][6]],
    "processing_time": "Immediate phone counseling; no formal processing as it's direct assistance service, not benefit approval.[1][5]",
    "waitlist": null,
    "forms": ["No specific forms for counseling; forms for related applications like MSP or LIS assisted during sessions.[3]"],
    "documents": ["Medicare card (if available).", "Prescription medication list.", "Healthcare provider and pharmacy information.", "Health conditions and upcoming procedures.", "Income and asset details.", "Other insurance information and card.", "Questions about Medicare."[1]]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Connecticut residents only.",
    "regional_variations": "Delivered via partnership with 5 Area Agencies on Aging (AAAs); contact local AAA for region-specific counseling, potential differences in providers or events but core services uniform.[5][6]",
    "offices_or_providers": ["Aging and Disability Services (ADS).", "5 Area Agencies on Aging (AAAs).", "Center for Medicare Advocacy, Inc."][6]
  },
  "official_source": "https://portal.ct.gov/ads/programs-and-services/choices",
  "gotchas": ["Not a direct financial aid or healthcare provider—purely counseling and assistance; people confuse it with MSP/LIS which pay premiums.", "No income/asset test for counseling itself, unlike programs it helps apply for.", "Out-of-state callers need local AAA contact via shiphelp.org.", "Proposed federal changes may affect agent disclosures of SHIP, but services remain free/unbiased.", "Family/caregivers can access even if not personally on Medicare."[1][3][5][7]],
  "data_shape_notes": "no income test for core counseling; statewide via regional AAAs; assists with tiered programs like MSP (income-based by household size: single/couple); free volunteer/staff network; focuses on Medicare navigation, not direct benefits."
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are set by federal guidelines (e.g., for 2026, consult current HHS Poverty Guidelines; not specified in sources for CT). Applies to full household income.[1][2][4][7]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "U.S. citizen or authorized to work", "Priority: Veterans and qualified spouses first, then individuals over 65, with disabilities, low literacy, limited English proficiency, rural residents, homeless/at risk, low employment prospects, or prior American Job Center users.[1][2]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time paid on-the-job training (average 20 hours/week) at non-profits/public facilities (e.g., schools, hospitals, senior centers, day-cares). Paid highest of federal/state/local minimum wage (bi-weekly in some cases). Includes career assessment, Individual Employment Plan, supportive services, specialized skills training, job placement assistance to unsubsidized jobs. Career tracks: home health aide, food service, customer service, office administration, stock clerk, retail sales.[2][3][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Associates for Training and Development (A4TD) at 203-461-2154 (Stamford, CT office serving CT)", "Website: www.a4td.org", "In-person: Associates for Training and Development, Stamford, CT 06831", "Possibly through local American Job Centers or subgrantees (contact A4TD for CT-specific partners)"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Likely due to funding limits and priority enrollment; not explicitly detailed for CT.",
    "forms": ["No specific form names/numbers listed; intake via provider."],
    "documents": ["Proof of age (ID)", "Proof of income (tax returns, pay stubs)", "Proof of unemployment", "Veteran status if applicable (DD-214 or spouse docs). Prepare family income details for 125% FPL check.[inferred from standard practices; sources do not list explicitly]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None specified; available across CT.",
    "regional_variations": "Administered by national grantee Associates for Training and Development (A4TD) with Stamford office; may use local subgrantees/partners varying by area, but no differing eligibility/benefits noted. Potential waitlist or slot variations by demand.[4]",
    "offices_or_providers": ["Associates for Training and Development (primary CT provider), Stamford, CT[4]"]
  },
  "official_source": "https://www.dol.gov/agencies/eta/seniors (U.S. DOL); CT-specific: https://portal.ct.gov (via aging services PDF)[2][4]",
  "gotchas": ["Transitional program only—positions temporary, not permanent jobs; 'bridge' to unsubsidized employment.", "Strict priority tiers may delay non-priority applicants (e.g., non-veterans under 65).", "Must be unemployed at enrollment; income counted for full family/household.", "Funded 90% federal/10% match; limited slots (~7,000 nationally).", "No asset test, but full income verification required.[1][2][3]"],
  "data_shape_notes": "National program with CT administered by non-profit grantee A4TD (not state agency); income at 125% FPL (household-based, annual federal table); priority tiers heavily influence access; 20 hr/wk fixed training wage at min wage; subgrantee network may create local access points."
}

{
  "name": "Connecticut Legal Assistance Program for Elders",
  "eligibility": {
    "age": 60,
    "income_limits": "Low-income status required, typically at or below 125-150% of federal poverty guidelines (exact dollar amounts not specified in sources; varies by program component, e.g., CVLC at less than 150% FPG). No full household size table provided.",
    "asset_limits": "Limited income and assets required for some components (e.g., Hartford program); specific counts/exemptions not detailed.",
    "other_requirements": ["Low-income individuals", "Residents of specific regions for certain providers (e.g., south central CT for NHLA)", "Consumer legal problems for CLPE", "Veterans for CVLC"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice, brief services, full representation, policy advocacy, community education, and referrals to low-cost attorneys; specific to elder law, consumer issues, Medicare appeals, veteran matters.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Varies by provider (e.g., NHLA via AOASCC referral, CLPE hotline 800-296-1467, CVLC via collaboration sites, CT Lawyers Legal Aid to the Elderly 860-273-8164)", "In-person: Regional offices (e.g., New Haven Legal Assistance, Waterbury Connecticut Legal Services)", "Website: portal.ct.gov/LTCOP/Your-Legal-Rights for resources"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["No specific form names/numbers identified"],
    "documents": ["Proof of age, income, residency, and details of legal issue (inferred; not explicitly listed)"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Regional providers (e.g., south central CT for NHLA/AOASCC, Hartford County, Waterbury, statewide hotline for CLPE)",
    "regional_variations": "Delivered through local agencies like New Haven Legal Assistance Association (south central), Connecticut Legal Services (Waterbury, Hartford), Consumer Law Project for Elders (statewide hotline); different focuses and funding sources by area.",
    "offices_or_providers": ["New Haven Legal Assistance Association (Elder Law Unit)", "Connecticut Veteran Legal Center (West Haven)", "Consumer Law Project for Elders (statewide)", "Connecticut Legal Services (Waterbury, Hartford)", "CT Lawyers Legal Aid to the Elderly"]
  },
  "official_source": "https://portal.ct.gov/LTCOP/Your-Legal-Rights",
  "gotchas": ["Not a single centralized program but a network of funded providers; eligibility and services vary by region/provider (e.g., consumer-only for CLPE, veterans for CVLC); must contact specific local agency; no uniform income/asset tables published; some require Area Agency on Aging referral."],
  "data_shape_notes": "Decentralized network of regional providers funded via Older Americans Act; no statewide uniform eligibility table or central application; services tiered by legal issue and provider focus."
}

{
  "name": "Connecticut Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; the program is available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a long-term care facility in Connecticut, including skilled nursing facilities, residential care homes, or assisted living/managed residential communities.", "Available to older adults and individuals with disabilities in these settings.", "Complaints or assistance can be initiated by residents, family members, legal guardians, or others acting on their behalf."][3][4][5]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigation and resolution of complaints related to care, rights, health, safety, and quality of life; provision of information and consultation to residents, families, and providers; education on resident rights; monitoring of state and federal laws with recommendations for improvements; recruitment, training, and supervision of Volunteer Resident Advocates to assist with concerns.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-388-1888 (toll-free statewide) or 860-424-5200", "Email: LTCOP@CT.GOV (for volunteer-related inquiries, but general complaints accepted)", "Website: https://portal.ct.gov/LTCOP for information and contacts"],
    "processing_time": "Not specified; program responds to and investigates complaints, but no formal processing timeline stated.",
    "waitlist": null,
    "forms": ["No specific application forms required for receiving services; complaints handled directly via phone or contact. Volunteer advocate applications include: Volunteer Resident Advocate Application, Volunteer Resident Advocate Verification Form, Volunteer Resident Advocate Reference Form, Conflict of Interest Screening Form."],
    "documents": ["No documents needed to request services or file a complaint. For volunteers: application documents, references, and conflict of interest screening."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services limited to residents in certified long-term care facilities across Connecticut (skilled nursing, residential care homes, assisted living).",
    "regional_variations": "Several regional ombudsmen assigned to specific counties; each works with local Volunteer Resident Advocates. No detailed differences in services, wait times, or operations by region specified.",
    "offices_or_providers": ["Statewide program with regional ombudsmen by county; central office contact via phone/email."]
  },
  "official_source": "https://portal.ct.gov/LTCOP",
  "gotchas": ["This is not a direct service provider (e.g., no healthcare, financial aid, or housing); it focuses solely on advocacy, complaint resolution, and rights protection.", "Strict confidentiality for all communications with residents, families, or guardians.", "Volunteers and staff must be free of conflicts of interest (e.g., cannot work for, own, or have immediate family in the assigned facility).", "Not for community-dwelling individuals; only for those in certified long-term care facilities.", "Families cannot use volunteer advocates if they have family in the specific facility."],
  "data_shape_notes": "no income test; advocacy-only for LTC facility residents statewide with regional ombudsmen; open to all without eligibility barriers beyond facility residency"
}

{
  "name": "Connecticut Private Pay Assisted Living Pilot Program",
  "eligibility": {
    "age": 65,
    "income_limits": "Must qualify financially for the Connecticut Home Care Program for Elders (CHCPE), which includes income assessment leading to mandatory 9% cost share or applied income payments. Specific dollar amounts not detailed in sources; refers to CHCPE criteria.[1][6]",
    "asset_limits": "Unmarried: less than $36,270. Married: less than $48,380. Spousal assessment protection exemption may allow qualification above limits.[2][4]",
    "other_requirements": [
      "Must qualify functionally for CHCPE (at risk of nursing home placement, needing assistance with bathing, dressing, eating, medications, toileting).",
      "Must reside in a participating Managed Residential Community (MRC) served by a participating Assisted Living Service Agency (ALSA).[1][6]"
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "Funding for assisted living services (personal care, nursing care) up to approximately $2,360-$2,900 monthly, based on Service Package Levels determined by weekly hours of personal care needed. Does not cover room and board. Examples: Core services $4.41 daily (~$137 monthly); Occasional (1-3.75 hours/week) $24.02 daily (~$745 monthly). State pays assisted living home directly.[1][2][3][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: 1-800-445-5394 or 860-424-4904[1]"
    ],
    "processing_time": "Not specified; after eligibility determination and slot offer, local Access Agency conducts needs assessment to develop plan of care.[1]",
    "waitlist": "Subject to wait list; limited slots (e.g., participation limited to 125 seniors).[1][3]",
    "forms": [],
    "documents": [
      "Documents for CHCPE financial and functional eligibility assessment (specifics not listed; prepare income, asset proofs for asset limits and cost share).[1][2][6]"
    ]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to approved private assisted living communities (participating MRCs served by ALSAs); fewer than 35 communities.[1][3]",
    "regional_variations": "Varies by availability of participating providers; no specific regional wait time data.[3]",
    "offices_or_providers": [
      "Examples: The Orchards at Southington[7]; participation slipped in recent years[3]"
    ]
  },
  "official_source": "https://portal.ct.gov/-/media/Departments-and-Agencies/DSS/Health-and-Home-Care/Community-Options/Private-Pay-Assisted-Living-Pilot.pdf",
  "gotchas": [
    "Does not pay room and board—only services; residents must cover housing costs.[1]",
    "Mandatory 9% cost share or applied income payments.[1]",
    "Limited slots and participating communities; wait lists common.[1][3]",
    "Aid levels (e.g., ~$2,900 max) may not fully bridge costs, leading to eventual nursing home transfer if funds deplete.[3]",
    "Must already reside in approved facility; designed for those who spent down assets.[1]",
    "Different from Assisted Living Demonstration Project (covers housing, but only 4 sites).[3]"
  ],
  "data_shape_notes": "Tied to CHCPE eligibility; service packages tiered by weekly personal care hours; limited to specific participating assisted living communities (fewer than 35); no statewide coverage."
}

{
  "name": "CHOICES Program",
  "eligibility": {
    "age": 65,
    "income_limits": "No income limits for core CHOICES counseling services, available to all Medicare-eligible individuals regardless of income. For related assistance programs like Medicare Savings Program (MSP): based on gross income (no assets counted); specific 2025 limits not detailed in sources but MSP has higher guidelines than federal LIS and covers Part B premiums. Extra Help/LIS: Full benefits up to specified levels (e.g., Level 1 for MSP recipients); CT recommends MSP application first due to no asset test and higher income thresholds. MED-CONNECT: Up to $85,000/year for full Medicaid/HUSKY, applicant income only (spouse not counted for eligibility determination).[6]",
    "asset_limits": "No asset limits for CHOICES counseling or MSP; assets not considered for MSP eligibility, only income.[4][6]",
    "other_requirements": ["Medicare-eligible: US citizens/permanent residents aged 65+ with 40 quarters (10 years) work history for premium-free Part A, or certain younger people (under 65) with SSA-approved disabilities receiving SSDI for 24 months.[4]", "Available to Medicare beneficiaries, families, and caregivers of all ages/income levels, with priority for low-income, disabled, rural, and non-English primary language speakers.[2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling on Medicare Parts A/B/C/D, Medicare Advantage, Medicare Supplement, Prescription Drug Coverage (Part D); enrollment assistance and plan comparisons; eligibility screening/application help for Medicaid, Medicare Savings Program (MSP, pays Part B premium and may cover Part A), Low-Income Subsidy/Extra Help; information/referral on aging issues, fraud detection; Benefits Check Up tool for confidential screening of benefits like tax relief, SSI.[2][3][6][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-994-9422 to speak with a counselor in your area.[5][10]", "Website: https://portal.ct.gov/ADS-CHOICES or https://portal.ct.gov/ADS (Department of Aging and Disability Services).[5][10]", "In-person/email/other: Contact local Area Agency on Aging (AAA) counselor; 5 AAAs partner statewide (e.g., North Central AAA, WCAAA at 203-757-5449).[7][9]", "Benefits Check Up tool via appointment or website (confidential, no personal info needed).[3]"],
    "processing_time": "Not specified; counseling available by appointment/phone/email.",
    "waitlist": null,
    "forms": ["No specific form for CHOICES counseling; application assistance provided for MSP/LIS/Medicaid (e.g., via DSS for MSP).[4][6]"],
    "documents": ["Not required for initial counseling; for assistance programs like MSP: income proof (e.g., SSI award letter, pay stubs); Medicare card beneficial but not mandatory.[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered through 5 regional Area Agencies on Aging (AAAs) with local counselors/providers (e.g., Agency on Aging of South Central CT, North Central AAA, WCAAA, Senior Resources EC); services offered in-person/phone/email based on local availability, potential differences in wait times or access by region.[1][2][7][9]",
    "offices_or_providers": ["5 Area Agencies on Aging (AAAs); Center for Medicare Advocacy; local examples: Windham CT, Coventry CT Senior Center, Bloomfield CT, etc.[2][3][8]"]
  },
  "official_source": "https://portal.ct.gov/ADS-CHOICES or https://portal.ct.gov/ADS/programs-and-services/choices[5][10]",
  "gotchas": ["Not a direct financial/long-term care benefits program but counseling/eligibility screening service; people confuse with Medicaid 'CHOICES' in other states. MSP/LIS applications handled separately via DSS, auto-qualifies LIS if approved for MSP (prefer MSP first: no assets, higher income). Targets Medicare navigation, not general elderly care. Volunteers must be certified, not insurance agents.[1][2][4][6]", "MED-CONNECT: Income up to $85k for full coverage but may require premium; only applicant income counts.[6]"],
  "data_shape_notes": "Statewide SHIP via 5 AAAs; no income/asset test for counseling; links to tiered programs like MSP (income-only, no assets) and MED-CONNECT ($85k cap, applicant-only income)"
}
